+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Handler (ID 30366).
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Handler"
+{
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesDocOnAfterTransferPostedInvoiceFields', '', false, false)]
+    local procedure OnCopySalesDocOnAfterTransferPostedInvoiceFields(var ToSalesHeader: Record "Sales Header"; SalesInvoiceHeader: Record "Sales Invoice Header"; OldSalesHeader: Record "Sales Header")
+    begin
+        // Clear Shopify Order Id and Shopify Order No when copying from a posted invoice
+        // This ensures the copied invoice is treated as a new document for Shopify export
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+    end;
+}

